# Expression class for linear arithmetic
class Expression:
    def __init__(self, name=None, coeff=1.0):
        self.terms = {}  # variable name (string) -> coefficient
        if name:
            self.terms[name] = coeff
    def __mul__(self, other):
        if isinstance(other, (int, float)):
            new = Expression()
            for k, v in self.terms.items():
                new.terms[k] = v * other
            return new
        return NotImplemented
    def __rmul__(self, other):
        return self.__mul__(other)
    def __add__(self, other):
        new = Expression()
        new.terms = self.terms.copy()
        if isinstance(other, Expression):
            for k, v in other.terms.items():
                new.terms[k] = new.terms.get(k, 0) + v
        elif isinstance(other, (int, float)):
            pass
        else:
            return NotImplemented
        return new
    def __radd__(self, other):
        return self.__add__(other)
    def __eq__(self, other):
        return LinearConstraint(self, other)
    def __repr__(self):
        return str(self.terms)

class LinearConstraint:
    def __init__(self, lhs, rhs):
        self.expr = (lhs, rhs)

class Namespace:
    def __init__(self, name):
        self.name = name
        self.vars = {}
    def define(self, key, lower, upper, types):
        self.vars[tuple(key)] = {'lower': lower, 'upper': upper, 'type': types}
    def __call__(self, key):
        return Expression(name=f"{self.name}({key})")

class Problem:
    def __init__(self):
        self.namespaces = {}
        self.constraints = []
        self.objective = None
        self.integrality_tolerance = type('T', (), {'value': None})
    def namespace(self, name):
        ns = Namespace(name)
        self.namespaces[name] = ns
        return ns
    def add_linear_constraints(self, expr):
        self.constraints.append(expr)
    def set_objective(self, expr):
        self.objective = expr

class Solver:
    def __init__(self, name):
        self._properties = {'name': name}
    def create_problem(self):
        return Problem()

